-- =====================================================================
-- === START: update_imgpath.sql
-- =====================================================================

-- =====================================================================
-- Convertire imgpath: din URL Supabase -> nume fisier local
-- Ruleaza in pgAdmin Query Tool DUPA data.sql
-- =====================================================================

-- Stergem prefixul Supabase Storage
UPDATE public."Evenimente"
SET imgpath = REPLACE(imgpath,
    'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/',
    '')
WHERE imgpath LIKE 'https://%';

-- Decodam URL-encoding (ex: "Event%20Test.png" -> "Event Test.png")
UPDATE public."Evenimente"
SET imgpath = REPLACE(imgpath, '%20', ' ')
WHERE imgpath LIKE '%\%20%' ESCAPE '\';

-- Verificare
SELECT id_event, name, imgpath FROM public."Evenimente" ORDER BY id_event;


-- === END: update_imgpath.sql



-- =====================================================================
-- === START: admin_migration.sql
-- =====================================================================

-- =====================================================================
-- Ticketa - Migrare ADMIN ROLE + suspendare conturi/evenimente
-- Ruleaza in pgAdmin DUPA toate celelalte SQL-uri
-- Idempotent: poate fi rulat de mai multe ori
-- =====================================================================
BEGIN;

-- =====================================================================
-- 1. Adaugare coloana is_suspended pe Users
-- =====================================================================
ALTER TABLE public."Users"
    ADD COLUMN IF NOT EXISTS is_suspended boolean NOT NULL DEFAULT false;

-- =====================================================================
-- 2. Adaugare coloana is_suspended pe Evenimente
-- =====================================================================
ALTER TABLE public."Evenimente"
    ADD COLUMN IF NOT EXISTS is_suspended boolean NOT NULL DEFAULT false;

-- Index util pentru filtrarea evenimentelor active (non-admin)
CREATE INDEX IF NOT EXISTS idx_evenimente_suspended ON public."Evenimente" (is_suspended);

-- =====================================================================
-- 3. Promovam un user existent la rol admin (Tudor Chirita - id 6)
--    sau creem unul nou daca nu exista
-- =====================================================================
UPDATE public."Users"
SET role = 'admin'
WHERE id_user = 6;

-- Daca nu exista user id 6, INSERT cont admin default (admin@ticketa.ro / parola: admin)
SELECT E'Admin', E'Principal', E'admin@ticketa.ro', E'admin', E'+40700000000', E'1990-01-01', E'admin', NULL, NOW()
WHERE NOT EXISTS (SELECT 1 FROM public."Users" WHERE role = 'admin');

COMMIT;

-- =====================================================================
-- Verificare
-- =====================================================================
SELECT 'Coloana is_suspended pe Users: ' ||
       (SELECT COUNT(*)::text FROM information_schema.columns
        WHERE table_name = 'Users' AND column_name = 'is_suspended') AS check_users_col;

SELECT 'Coloana is_suspended pe Evenimente: ' ||
       (SELECT COUNT(*)::text FROM information_schema.columns
        WHERE table_name = 'Evenimente' AND column_name = 'is_suspended') AS check_event_col;

SELECT 'Useri admin: ' || COUNT(*)::text AS check_admin
FROM public."Users" WHERE role = 'admin';

SELECT id_user, fname, lname, email, role, is_suspended
FROM public."Users" WHERE role = 'admin';


-- === END: admin_migration.sql



-- =====================================================================
-- === START: create_admin_account.sql
-- =====================================================================

-- =====================================================================
-- Ticketa - Cont admin nou: admin@ticketa.ro / 123456
-- Ruleaza in pgAdmin DUPA admin_migration.sql (care a adaugat coloana is_suspended)
-- Idempotent: poate fi rulat de mai multe ori
-- =====================================================================
BEGIN;

-- Stergem versiunea veche daca exista (din admin_migration.sql care punea parola 'admin')
DELETE FROM public."Users" WHERE email = 'admin@ticketa.ro';

-- Cont admin nou
     E'1990-01-01', E'admin', NULL, NOW(), false);

COMMIT;

-- Verificare
SELECT id_user, fname, lname, email, role, is_suspended, creation_date
FROM public."Users"
WHERE email = 'admin@ticketa.ro';


-- === END: create_admin_account.sql



-- =====================================================================
-- === START: fix_sequences.sql
-- =====================================================================

-- =====================================================================
-- Ticketa - Fix pentru sequence-urile IDENTITY
-- Ruleaza in pgAdmin DUPA toate scripturile cu INSERT-uri explicite
-- (data.sql, iabilet_top21.sql, virtual_events_10.sql, etc.)
--
-- Cauza: cand inserezi cu id explicit, sequence-ul NU se auto-incrementeaza.
-- Aplicatia (care insereaza fara id) genereaza apoi id-uri care exista deja.
-- =====================================================================

-- Users
SELECT setval(pg_get_serial_sequence('public."Users"', 'id_user'),
              GREATEST(COALESCE((SELECT MAX(id_user) FROM public."Users"), 0), 1));

-- Orase
SELECT setval(pg_get_serial_sequence('public."Orase"', 'id_oras'),
              GREATEST(COALESCE((SELECT MAX(id_oras) FROM public."Orase"), 0), 1));

-- Evenimente
SELECT setval(pg_get_serial_sequence('public."Evenimente"', 'id_event'),
              GREATEST(COALESCE((SELECT MAX(id_event) FROM public."Evenimente"), 0), 1));

-- Bilet
SELECT setval(pg_get_serial_sequence('public."Bilet"', 'id_bilet'),
              GREATEST(COALESCE((SELECT MAX(id_bilet) FROM public."Bilet"), 0), 1));

-- Cos
SELECT setval(pg_get_serial_sequence('public."Cos"', 'id_cos'),
              GREATEST(COALESCE((SELECT MAX(id_cos) FROM public."Cos"), 0), 1));

-- Cos_Bilet
SELECT setval(pg_get_serial_sequence('public."Cos_Bilet"', 'id_cos_bilet'),
              GREATEST(COALESCE((SELECT MAX(id_cos_bilet) FROM public."Cos_Bilet"), 0), 1));

-- =====================================================================
-- Verificare: fiecare sequence trebuie sa fie >= MAX(id) corespunzator
-- =====================================================================
SELECT 'Users'      AS tabel, MAX(id_user)      AS max_id, currval(pg_get_serial_sequence('public."Users"',     'id_user'))     AS seq_curent FROM public."Users"
UNION ALL SELECT 'Orase',     MAX(id_oras),  currval(pg_get_serial_sequence('public."Orase"',     'id_oras'))     FROM public."Orase"
UNION ALL SELECT 'Evenimente',MAX(id_event), currval(pg_get_serial_sequence('public."Evenimente"','id_event'))   FROM public."Evenimente"
UNION ALL SELECT 'Bilet',     MAX(id_bilet), currval(pg_get_serial_sequence('public."Bilet"',     'id_bilet'))   FROM public."Bilet"
UNION ALL SELECT 'Cos',       MAX(id_cos),   currval(pg_get_serial_sequence('public."Cos"',       'id_cos'))     FROM public."Cos"
UNION ALL SELECT 'Cos_Bilet', MAX(id_cos_bilet), currval(pg_get_serial_sequence('public."Cos_Bilet"','id_cos_bilet')) FROM public."Cos_Bilet";


-- === END: fix_sequences.sql

