INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (7, E'Musicalul Invizibilii', E'„Invizibilii” este un musical românesc cu tematică contemporană, ce combină muzică, dans şi proiecţii multimedia. Un spectacol care vorbeşte despre visuri, identitate şi supravieţuire în societate, adresat publicului larg.', E'Teatrul Național București, Bd. Nicolae Bălcescu 2, Sector 1, București', E'2025-12-05 19:30:00+00', E'Armonie Productions', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/musicalul_invizibilii.png', E'București', E'fizic', 600, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (17, E'Turneu Paraziții – Underground Tour', E'Concert hip‑hop cu grupul Paraziții în turneu „Underground Tour” – show energic, public numeros, freestyle şi vibe de club/arena, dedicat fanilor underground.', E'Form Space, Str. Stadionului 4, Cluj-Napoca, Județ Cluj', E'2025-11-30 21:00:00+00', E'Paraziții', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/parazitii.png', E'Cluj-Napoca', E'fizic', 1000, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (1, E'RICKY MARTIN LIVE', E'Superstarul internaţional Ricky Martin revine în România pe 16 decembrie 2025 cu spectacolul „Ricky Martin LIVE”, ce promite un show complet: trupă live, dansatori, proiecţii video, efecte de lumină şi hituri precum „Livin’ la Vida Loca” şi „She Bangs”.', E'Romexpo, Bd. Mărăști 65-67, Sector 1, București', E'2025-12-16 20:00:00+00', E'Events Romania', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/ricky_martin_live.png', E'București', E'fizic', 1000, NULL);
