INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (5, E'BEACH, PLEASE! Festival 2026', E'Festivalul „BEACH, PLEASE! 2026” aduce la malul mării, în staţiunea Costinești, muzică live, DJ seturi, zone de relaxare, activităţi de zi şi petreceri pe plajă — o experienţă de vară şi festival pentru tineri.', E'Costinești Beach, Str. Tineretului, Costinești, Județ Constanța', E'2026-07-25 12:00:00+00', E'Global Records', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/beach_please2.png', E'Costinești', E'fizic', 5000, NULL);
